-- ----------------------------------------------------------------------------
-- KnowledgeGaps: Known unknowns and missing procedural coverage. Explicit ERB-PKO extension used to govern scope and prevent silent incompleteness.
-- ----------------------------------------------------------------------------
INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-close-dual-outage', 'close-v1.1.0', 'close-02', 'No validated fallback exists for simultaneous ERP and signed-snapshot repository outage.', 'High', 'Blocking', 'Resolved', 'controller', '2026-06-20T09:00:00-05:00', 'Resolved by adding offline signed export escrow.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-policy-delivery-receipts', 'policy-v1.0.0', 'policy-08', 'SMS provider delivery receipts are not always final for ported numbers.', 'Medium', 'NonBlocking', 'Open', 'communications-manager', '2026-07-18T16:00:00-05:00', 'Pilot secondary delivery-status reconciliation.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-close-sod-unwitnessed', 'close-v1.1.0', 'close-05', 'req-close-separation stated the preparer may not be the final approver, but nothing evaluated it. The control existed only as prose in a Requirements row, so a violation would have been invisible.', 'High', 'Blocking', 'Resolved', 'controller', '2026-07-19T17:30:00-05:00', 'Resolved by StepExecutions.ViolatesSeparationOfDuties, which counts preparation steps in the same procedure execution performed by the agent now approving. Verified by staging a breach (maria-chen approving se-close05 after preparing se-close03): the witness read TRUE. The staged breach was reverted; the control now reads FALSE because separation genuinely holds, not because nothing is checking.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-close-cadence-unmeasured', 'close-v1.1.0', NULL, 'StewardshipAssignments promised a 90-day review cadence for close-v1.1.0 and 60 days for policy-v1.0.0. Both the promise and the actual review history were in the model and nothing compared them, so a lapsed cadence was invisible.', 'Medium', 'NonBlocking', 'Resolved', 'process-steward', '2026-07-19T18:00:00-05:00', 'Resolved by ReviewEvents.ExceedsPromisedCadence and PromiseAndBehaviorDisagree, which compare DaysSinceReviewed against the cadence promised by the version''s stewardship assignment. Surfacing the real Q1 review (review-close-q1) showed the witness firing on genuine history: 121 days elapsed against a 90-day promise. The Q2 review closed the lapse, so current state reads compliant.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-roles-unauditable-holders', 'close-v1.1.0', NULL, 'Five of twelve roles were held only by a denormalized Roles.CurrentAgent pointer with no RoleAssignments row: communications-manager, knowledge-authority, process-steward, close-automation, policy-drafting-agent. The convenience pointer claimed a holder the auditable time-bounded table could not confirm, so provenance for anything those roles touched was unverifiable.', 'High', 'NonBlocking', 'Resolved', 'knowledge-authority', '2026-07-19T18:20:00-05:00', 'Surfaced by Agents.IsStillEngaged, which counts CURRENT RoleAssignments rather than trusting Roles.CurrentAgent. amina-yusuf read as not engaged, which made kf-policy-channel an IsUndefendableTacitClaim. Resolved by recording the five missing time-bounded assignments. The witness stays: it is the only thing that distinguishes a real appointment from a denormalized pointer.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-policy-consent-unenforced', 'policy-v1.0.0', 'policy-07', 'comm-sms-policy set ConsentRequired=true and exc-no-sms-consent documented the suppress-and-email handling, but no per-recipient delivery record existed, so a send to a non-consenting recipient was structurally invisible. req-policy-consent was a blocking control with zero satisfaction records.', 'Critical', 'Blocking', 'Resolved', 'employment-counsel', '2026-07-19T18:40:00-05:00', 'Resolved by the Recipients and MessageDeliveries tables plus MessageDeliveries.IsConsentViolation. Proven on md-003, a real SMS to a never-consented recipient, which the witness flags while correctly NOT flagging md-004 (consent revoked, properly suppressed under exc-no-sms-consent) or md-006 (unreachable, failed, HR case opened). Recipient re-consented; the delivery row is retained as evidence.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-policy-quiet-hours-unenforced', 'policy-v1.0.0', 'policy-07', 'comm-sms-policy defined a 20:00-08:00 quiet window and nothing compared a send time against it.', 'High', 'Blocking', 'Resolved', 'employment-counsel', '2026-07-19T18:40:00-05:00', 'Resolved by MessageDeliveries.IsInsideQuietWindow and IsQuietHoursViolation, proven on md-005 (21:00 send). QuietHoursStartHour is stored rather than parsed: VALUE(LEFT("20:00",2)) does not translate — the transpiler casts the string to a timestamp and the view errors.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-policy-unauthorized-sends', 'policy-v1.0.0', 'policy-07', 'MessageTemplates carried Status="Approved" as a bare string with no approval record behind it, and nothing evaluated a send BEFORE transmission. Every gate the communication policies define — consent, quiet hours, length, opt-out, approval — was checkable only after the fact, if at all.', 'Critical', 'Blocking', 'Resolved', 'communications-manager', '2026-07-19T19:00:00-05:00', 'Resolved by the SendIntents table and IsClearedToSend, which gates a proposed send on permission, timing, content, and authorization before it happens, and names the blocking gate. Proven across seven intents: Timing blocks a 21:00 send, Content blocks an oversized body and one missing the STOP phrase, Permission blocks an unreachable recipient. Authorization blocked ALL sends until tmpl-policy-sms received a real approval record (tap-sms-001) — the pipeline had been transmitting under a template nobody had attributably approved.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

