-- ----------------------------------------------------------------------------
-- WitnessLoops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- ----------------------------------------------------------------------------
INSERT INTO witness_loops (witness_loop_id, loop_number, title, premise, started_at, completed_at, semantic_type_iri)
VALUES ('loop-01', 1, 'The founding questions', 'The model specified obligations precisely and witnessed their breach almost nowhere. Requirements, verifications, exceptions, and communication policies were all stated with real precision, and in each case the execution-side counterpart that would catch a violation was missing. Loop 1 asks each of the twelve named roles what it actually needs to know, and invents the atomic predicates required to answer.', '2026-07-19T17:00:00-05:00', NULL, 'urn:effortless:pko-extension#WitnessLoop') ON CONFLICT (witness_loop_id) DO UPDATE SET loop_number = EXCLUDED.loop_number, title = EXCLUDED.title, premise = EXCLUDED.premise, started_at = EXCLUDED.started_at, completed_at = EXCLUDED.completed_at, semantic_type_iri = EXCLUDED.semantic_type_iri;

-- ----------------------------------------------------------------------------
-- RoleQuestions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- ----------------------------------------------------------------------------
INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-blocking-unmet-on-my-step', 'finance-analyst', 'loop-01', 'On the steps I personally executed, did any of them close out while a BLOCKING requirement was still not fully satisfied?', 'I executed se-close03 (Reconcile material accounts), which carries TWO blocking requirements via sr-c03a (req-close-balance) and sr-c03b (req-close-evidence). Today the model records SatisfactionLevel as free text and nothing compares it against IsBlocking. If I close a step with a PartiallySatisfied blocking control — exactly the shape sat-policy-legal is in right now — the package moves on and nobody is told. I want that to be a computed red flag on my own row before it becomes an audit finding on my name.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-blocking-never-evaluated', 'finance-analyst', 'loop-01', 'Which blocking requirements were attached to a step I ran but never got a satisfaction record at all — not satisfied, not unsatisfied, just never assessed?', 'This is the failure mode that scares me more than a recorded ''Unsatisfied''. sr-c03b binds req-close-evidence to close-03. I ran close-03 as se-close03. There is no RequirementSatisfactions row for that pairing. The model shows green because absence reads as silence, not as a gap. An unevaluated blocking control is indistinguishable from a passed one, and that is the exact thing SOX testing is designed to catch.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-evidence-binding-stale', 'finance-analyst', 'loop-01', 'When I attested my reconciliation, was the underlying ledger data actually fresh — or was I certifying against a source that had already gone stale under its own SLA?', 'OperationalBindings.IsFresh already exists and works, but it is evaluated against NOW() and lives on a table nothing in the execution story reads. My step execution has no idea whether the resources it depended on were inside their freshness SLA. se-close02 already recorded a 17-minute feed against a 15-minute SLA and it took a human writing prose into a Deviation field to surface it. I want that connected structurally, because next time the prose might not get written.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-my-late-steps-unexplained', 'finance-analyst', 'loop-01', 'Which of my steps ran long without anybody recording why — and of those, which ones had an exception available that nobody invoked?', 'StepExecutions.IsLate already works. But ''late'' on its own is not a finding; late-and-unexplained is. se-close03 is mine and it ran nearly 19 hours. If that overran the expected duration and the Deviation field is empty, I have an undocumented overrun sitting on my name. And exc-ledger-outage exists precisely for the close-02 condition — if it was never invoked, the model should say that out loud instead of letting a blank Deviation stand in for ''nothing happened''.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-verification-declared-never-performed', 'finance-analyst', 'loop-01', 'For every step I ran that had a declared verification, did anybody actually perform it and record the observed signal — or did I just get a PASS with nothing behind it?', 'StepVerifications is entirely spec-side. verify-reconciliation declares that close-03 must show unexplained-material-variance = 0. I ran close-03. My StepExecution says VerificationResult=PASS. But there is no row anywhere recording what the signal ACTUALLY read. The PASS is an unbacked assertion typed into a field. If an auditor asks me to produce the observed value, the model has nothing — and a skipped verification looks identical to a passed one.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-separation-of-duties', 'controller', 'loop-01', 'Did the same agent both prepare and approve any part of this close? req-close-separation says the preparer may not be the final approver — show me that it actually held, on exec-close-2026-q2, computed and not asserted.', 'This is the single highest-value gap in the model and it is my control. req-close-separation is IsBlocking=true, bound to close-05 via sr-c05, and sat-close-separation records SatisfactionLevel=''Satisfied'' with the evidence string ''Preparer and reviewer were different agents.'' That string is a human typing a conclusion into a text field. NOTHING compares se-close03.ExecutedByAgent (maria-chen) against se-close05.ExecutedByAgent (devon-okafor) or se-close06.ExecutedByAgent (priya-raman). Segregation of duties is the control SOX cares about most and in this model it is prose. If maria-chen executed both the preparation and the approval tomorrow, sat-close-separation would still say ''Satisfied'' and the model would agree.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-approval-authority-valid', 'controller', 'loop-01', 'Every approval on this close — was it given by an agent who actually held the required role AT THE TIME they approved, not just someone who holds it today?', 'req-close-human-approval is blocking and says controller and CFO approvals must be human-confirmed. sat-close-human records ''Satisfied'' because a human name appears in a field. But nothing checks that the approving agent held the approving role. RoleAssignments proves this is not paranoia: ra-old-variance shows maria-chen held variance-review-agent until 2026-03-31 and ra-new-variance shows variance-ai took it on 2026-04-01. Role-holding is time-bounded and it genuinely changes. If someone approves close-06 who is not the CFO, or who was the CFO last quarter but not this one, I need that computed. And exc-cfo-unavailable explicitly permits delegation to an Acting CFO ''never to the preparer'' — so an authority check that cannot see delegation is incomplete.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-blocking-control-inoperative', 'controller', 'loop-01', 'Which of my blocking close controls are structurally incapable of failing — declared, bound to a step, and yet with no mechanism that could ever produce a negative result?', 'req-close-cutoff, req-close-balance, req-close-separation, and req-close-evidence are all IsBlocking=true. All four are pure prose. A control that cannot fail is not a control, it is a comment. Before I sign anything I want a list of my own controls ranked by whether they can actually operate. This is the meta-question — it is about the model''s ability to hold me accountable, and it is the one I would ask first if I were the external auditor rather than the controller.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-execution-diverged-from-spec', 'controller', 'loop-01', 'Give me one number per close: did exec-close-2026-q2 actually conform to close-v1.1.0, and if not, how far off was it?', 'ProcedureExecutions has ZERO derived fields. The parent of the entire execution story makes no claim whatsoever — it has a status someone typed and two timestamps. Every failure signal in this model lives on child rows, so to know whether a close was clean I have to read twelve StepExecutions and six RequirementSatisfactions by hand. That is not a control environment, that is a filing cabinet. I want conformance to be a computed property of the execution, so that ''the close was clean'' is a claim the model makes and can be wrong about.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-ai-agent-approved-meaning', 'controller', 'loop-01', 'Did any AI agent or automated pipeline execute a step that requires human confirmation, or sign off on something a human was supposed to own?', 'req-close-human-approval and req-policy-human-approval both say a human must approve. Steps carries RequiresHumanConfirmation as a raw boolean and Agents carries AgentKind — Human, AIAgent, AutomatedPipeline — and NOTHING compares them. variance-ai executed se-close04. policy-drafting-ai executed se-policy03. Both fine today because those steps are not approval steps. But ra-old-variance to ra-new-variance shows this org actively migrates work from humans to AI agents, and the control that is supposed to stop that migration reaching an approval step is prose. This is the control I expect to matter most over the next two years and it currently does not exist.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-cfo-can-i-sign', 'cfo', 'loop-01', 'Can I sign the attestation for exec-close-2026-q2 — yes or no — and if no, name the blocker.', 'This is the only question I actually have. Today the model answers it with ProcedureExecutions.ExecutionStatus=''Completed'', which is a string somebody typed into a field. My signature carries personal liability under Section 302. I need attestation-readiness to be a computed conjunction of every blocking control, such that if ANY control did not operate, the model says no and names it. A green status that cannot go red is worse than no status at all, because it manufactures false comfort at exactly the moment I am least able to verify it myself.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-cfo-approving-on-unfit-version', 'cfo', 'loop-01', 'Am I being asked to approve an execution of a procedure version that is itself overdue for review, or that has an open change request against it?', 'I sign against close-v1.1.0. If that version''s periodic review lapsed, or if there is an open ChangeRequest saying the procedure is known to be wrong, then I am attesting to conformance with a specification that the organization itself no longer stands behind. ReviewEvents.IsOverdue already works and ChangeRequests.IsOpen already works, but neither is connected to the execution I am signing. The version''s fitness and the execution''s conformance are two different questions and I need both answered before I sign, not one.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-cfo-approval-was-actually-verified', 'cfo', 'loop-01', 'My own approval on se-close06 — is there anything behind it other than the fact that I clicked approve?', 'verify-cfo declares that close-06 must show cfo-approval = APPROVED. se-close06 says VerificationResult=PASS. But the PASS and the approval are the same act: I approved, therefore the verification that I approved passes. That is circular, and it is my name on the circle. sat-close-human''s evidence reads ''Human CFO approval recorded'' — recorded by whom, against what? I want to know whether my approval rests on independently verified upstream evidence or whether the model is simply reflecting my own click back at me.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-cfo-who-actually-held-authority', 'cfo', 'loop-01', 'For every approval in this close, tell me the human who was personally accountable — and whether an exception was used to route authority away from the person who normally holds it.', 'exc-cfo-unavailable exists and says approval may be delegated to a designated Acting CFO, ''never to the preparer''. That last clause is a control and it is prose inside a text field. If I was unavailable and someone approved in my place, I need the model to show me who, under what authority, and whether the never-to-the-preparer condition held. Right now an exception can be invoked with no trace at all — nothing links an execution back to the exception it used. From my seat that means delegated authority is entirely invisible, which is the exposure I am least willing to carry.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-cfo-am-i-being-told-everything', 'cfo', 'loop-01', 'Across everything I am signing, is there any control claim in this model that rests on a human typing a conclusion rather than on something computed?', 'This is the question behind all my other questions. sat-close-separation says ''Preparer and reviewer were different agents.'' sat-close-human says ''Human CFO approval recorded.'' Both are prose conclusions in an Evidence field, both assert that a control operated, and neither is checkable. I want the model to distinguish between a control that was COMPUTED to have held and one that was ASSERTED to have held, and to tell me how much of my attestation rests on the second kind. If most of my assurance is assertion, I want to know that before I sign, not after.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-steward-cadence-breach', 'process-steward', 'loop-01', 'For close-v1.1.0 I promised a 90-day review cadence and for policy-v1.0.0 a 60-day cadence. Is the ACTUAL interval since the last review already longer than the cadence I promised?', 'ReviewCadenceDays is a promise. ReviewEvents.ReviewedAt is the behavior. Today the model stores both and compares neither, so a stewardship assignment can sit in permanent silent breach while ReviewEvents.IsOverdue stays FALSE because NextReviewDue was hand-set to a date that has nothing to do with the promised cadence. I need the promise and the behavior in the same row.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-steward-orphan-versions', 'process-steward', 'loop-01', 'Which procedure versions have no steward at all? close-v1.0.0 is Archived but still referenced by ProcedureVersionLinks — does anyone own it?', 'An unstewarded version is nobody''s problem until it is everybody''s problem. There are 3 ProcedureVersions and only 2 StewardshipAssignments; the model has never once been asked to notice the difference. Orphaned versions accumulate silently as new versions ship and the old assignment is never extended or retired.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-steward-untested-fallbacks', 'process-steward', 'loop-01', 'close-04-fallback-close-03 and policy-07-fallback-policy-06 are the paths we take when things go wrong. Have they EVER been walked in a real execution?', 'There are 19 StepTransitions and only 12 StepExecutions. Every Fallback and Alternative transition in this model is untested. Untested fallbacks are exactly where an outage becomes an incident — the day the ERP is down is the wrong day to discover the recovery path was never real. Nothing in the model witnesses this.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-steward-published-with-blocking-gap', 'process-steward', 'loop-01', 'Is any procedure version live with an Open BLOCKING knowledge gap against it?', 'gap-close-dual-outage was Blocking and is now Resolved — good. But nothing stops the next one from staying Open while the version keeps shipping. ProcedureVersions.CountOfOpenKnowledgeGaps exists but is blind to BlockingKind, so a Blocking gap and a cosmetic one count the same. IsReadyForExecution then fails on trivia and stays silent on the thing that should stop the line.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-steward-stalled-change-requests', 'process-steward', 'loop-01', 'cr-policy-delivery was requested on 2026-07-19 and has no DecidedAt. How long has it been sitting, and is that longer than we tolerate?', 'A change request with no decision is a decision — to do nothing — but it never announces itself. The model stores RequestedAt and DecidedAt and computes neither the interval nor a staleness verdict. Since cr-policy-delivery is the vehicle for closing gap-policy-delivery-receipts on a live policy version, its stall is load-bearing.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-authority-orphaned-provenance', 'knowledge-authority', 'loop-01', 'kf-close-fx-time, kf-close-top-ten and kf-close-judgment all trace to devon-okafor via elicit-close-shadow. If Devon''s controller role assignment ends, which of our beliefs lose their witness?', 'This is institutional memory decay in its purest form. A knowledge fragment is a claim; its SourceAgent is the person who can defend it. When that person''s RoleAssignment.ValidTo passes, the claim survives in the database but its warrant evaporates — nobody left can say why we believe it. The chain KnowledgeFragments -> SourceAgent -> RoleAssignments.ValidTo is fully modeled and never traversed. Three of seven fragments hang off one human.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-authority-non-approved-dependency', 'knowledge-authority', 'loop-01', 'kf-policy-manager-route is Status=Reviewed, not Approved, so IsCurrentlyValid is FALSE. policy-08 is a live step. Are we running a procedure on knowledge I never approved?', 'This is the exact failure the separation of Reviewed and Approved exists to catch, and nothing catches it. The fragment describes the 48-hour manager-routing behavior that exc-unreachable depends on. It is attached to a step in an Approved procedure version, it is being relied upon operationally, and it has never passed my desk. The model knows every piece of this and joins none of it.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-authority-stale-elicitation', 'knowledge-authority', 'loop-01', 'elicit-close-shadow ran on 2026-04-03 and elicit-policy-workshop on 2026-05-10. How old is the evidence behind each belief, and at what age do I stop trusting a shadowing session I have not repeated?', 'Knowledge does not announce its own expiry. Every fragment here has ValidTo=null, which reads as ''valid forever'' — but a Tacit claim captured by shadowing one controller for three hours in April is a snapshot of a practice that drifts. I want the age of the EVIDENCE, not the age of the record, and I want it graded by how fragile the elicitation method was.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-authority-known-unknowns', 'knowledge-authority', 'loop-01', 'What do we know that we do not know? gap-policy-delivery-receipts has been Open since 2026-07-18 with a ResolutionPlan and no owner activity. How long do our acknowledged ignorances stay acknowledged and unresolved?', 'A KnowledgeGap is the most honest object in this model: a written admission of what we do not know. But an admission with no clock on it converts into a permanent condition. KnowledgeGaps has IdentifiedAt and a Status and computes no age, no ownership currency, and no relationship between a gap''s severity and how long we have tolerated it. Known unknowns that never age are not being managed, they are being filed.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-authority-unwitnessed-change', 'knowledge-authority', 'loop-01', 'cr-close-timestamp altered a blocking control on close-v1.1.0 and was decided by me. Did any semantic change to a live procedure reach production without a change request and without a review event behind it?', 'My authority is over what counts as true, which means every change to the meaning of a live procedure must trace to a decision I made. close-v1.1.0 was ModifiedAt 2026-07-02T15:00 by maria-chen; review-close-q2 happened at 16:00 and cr-close-timestamp was raised at 16:30. That ordering is fine. But nothing in the model checks the ordering, so an edit that PRECEDES no review and no change request looks identical to a governed one. Provenance of change is as much an epistemic question as provenance of belief.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-counsel-sms-without-consent', 'employment-counsel', 'loop-01', 'Did we send an SMS to any recipient who had not given SMS consent at the moment we sent it?', 'comm-sms-policy sets ConsentRequired=true. Every SMS to a non-consenting recipient is an independent statutory violation with per-message damages, and the exposure scales with the size of the affected population. Right now the model cannot answer this at all -- there are no per-recipient send records -- so counsel cannot sign off on policy-04, cannot certify to an outside regulator, and cannot even scope the exposure. The absence of the record IS the legal problem: unanswerable and non-compliant look identical from the outside.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-counsel-quiet-hours-breach', 'employment-counsel', 'loop-01', 'Did any SMS go out between 20:00 and 08:00 in the recipient''s own local time?', 'comm-sms-policy declares QuietHoursStart 20:00 / QuietHoursEnd 08:00. Quiet-hours restrictions on non-emergency messaging are statutory in several jurisdictions and contractual in others, and a night-time text to an employee about an employment policy change is exactly the fact pattern that generates a complaint. The window wraps midnight, which is where naive implementations quietly get it wrong -- and a witness that is wrong in the safe direction is worse than no witness, because it manufactures false assurance.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-counsel-unreachable-not-acknowledged', 'employment-counsel', 'loop-01', 'For every recipient we could not reach, did we correctly refrain from marking their acknowledgement complete?', 'exc-unreachable is explicit: create an HR case, route to the manager, and do NOT mark acknowledgement complete. A falsely-recorded acknowledgement is the single most dangerous artifact in this entire model -- it is an affirmative written misrepresentation that the employee received and accepted a policy change, and it is exactly the document that gets subpoenaed in a wrongful-termination or unpaid-notice claim. Deemed-acknowledgement by silence is not acknowledgement. I would rather have zero acknowledgements than one fabricated one.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-counsel-retention-evidence', 'employment-counsel', 'loop-01', 'Do we still hold the exact text of every message we sent, for the full 2555-day retention period the policy commits us to?', 'Both comm-sms-policy and comm-email-policy declare RetentionDays=2555 -- seven years. That is a commitment we made in writing, and in a dispute the question is never ''what did the template say'', it is ''what did THIS employee actually receive''. Templates contain variable substitutions; the rendered text is the evidence. If a delivery record exists but its rendered body is empty, we have a receipt with no document behind it, and the adverse inference runs against us.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-counsel-legal-review-gated-send', 'employment-counsel', 'loop-01', 'Did any message go out before my legal review of the underlying policy version was actually complete?', 'policy-04 is my step, and right now se-policy04 is InProgress with VerificationResult PENDING. If policy-07 sends started while my review was still open, then employees received a policy communication that no lawyer had cleared -- and the model would show that in black and white. This is not process pedantry: an unreviewed employment-policy communication can create a binding representation to the workforce, and once it is sent we cannot un-send it. The ordering constraint is the control.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-comms-oversized-sms', 'communications-manager', 'loop-01', 'Did any SMS we sent exceed 160 characters or split into more than 3 segments?', 'comm-sms-policy sets MaxMessageLength=160 and MaxSegments=3, and I own that policy. An over-length SMS silently splits at the carrier, arrives out of order, and -- this is the part that actually hurts -- the opt-out language is in the LAST segment, so an over-length message can strip the STOP instruction off the end of what people actually read. I have the template body and I have the policy limit sitting in the same rulebook and nothing compares them. This is the most embarrassing category of failure because it was computable from data we already had.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-comms-approval-authority', 'communications-manager', 'loop-01', 'Was every template we actually sent approved by me -- the ApprovalRole the policy names -- before it went out?', 'Both channel policies name communications-manager as ApprovalRole. Right now tmpl-policy-sms.Status says ''Approved'' and there is not one byte of data anywhere saying WHO approved it or WHEN. A status string with no approver behind it is not an approval, it is a claim. I need to be able to point at a row and say ''that is my name, that is the timestamp, that is the version of the text I saw''. Otherwise when something goes out wrong, ''approved'' means nothing and the accountability lands wherever it lands.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-comms-optout-present', 'communications-manager', 'loop-01', 'Did every SMS we actually transmitted carry the approved opt-out text?', 'comm-sms-policy RequiredContent says ''Short notice, secure link, approved opt-out text'' and the approved template ends with ''Reply STOP to opt out of SMS; email notices continue.'' The opt-out is not decoration -- it is the mechanism by which consent stays meaningful, and it is the thing that gets clipped first when a message runs long. I want to check the RENDERED body, not the template, because that is what the employee saw. A policy that declares RequiredContent and never verifies it is a policy that documents an intention.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-comms-deliverability', 'communications-manager', 'loop-01', 'For this policy run, what fraction of the affected population actually received something -- and how many are sitting in a bounced or failed state that nobody is working?', 'This is the question I get asked in the Monday stand-up and I currently answer it from a spreadsheet somebody built by hand. It is also the operational face of my own open item gap-policy-delivery-receipts and the change request I already filed, cr-policy-delivery. A bounce that nobody triages is functionally identical to never having sent the message, except that it produces a record that makes it LOOK like we did. That is the failure mode I most want visible.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-comms-template-drift', 'communications-manager', 'loop-01', 'Has any template been edited since I approved it, and did we send the edited version under cover of my old approval?', 'This is the failure I have actually lived through. A template gets approved, then somebody makes ''a tiny wording fix'' to the body, and the Status field still cheerfully says Approved because nothing ever reset it. The approval attaches to a version of the text, not to a row id. If the body changed and the approval did not, then my name is on something I never read -- and given that these are employment-policy communications, that is not a governance abstraction, that is my name on a legal notice I did not review.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-publisher-may-i-transmit', 'notification-publisher', 'loop-01', 'Before I transmit, am I permitted to use this channel for this recipient at all?', 'I am the component that actually calls the carrier. Every other question in this rulebook is asked after I have already acted, which means every other question is asked too late. I need one column I can read that says PERMITTED or NOT PERMITTED, computed from the policy rows rather than from anything hardcoded in my own configuration -- because my configuration is not the source of truth and should not be. If I cannot determine consent, the answer must be no. An unevaluable rule is a refusal, not a pass.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-publisher-may-i-transmit-now', 'notification-publisher', 'loop-01', 'Before I transmit, is the current moment inside a window this channel forbids?', 'Timing is the one gate I can get right unilaterally and the one that is easiest to get wrong silently. My scheduler runs continuously; nothing about being invoked at 22:40 tells me I should not act. The quiet-hours window is recipient-local and it wraps midnight, so 06:15 is forbidden even though six is less than twenty. I need this evaluated as data on the intent row rather than as arithmetic inside my own code, because arithmetic inside my own code is exactly what nobody can audit and exactly what drifted from the policy in the first place.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-publisher-is-this-content-permitted', 'notification-publisher', 'loop-01', 'Before I transmit, is the exact text I am holding within this channel''s content rules?', 'I render the body; therefore I am the last component that can measure it before it becomes a fact. The template can be compliant and my rendered output still not be, because I am the one substituting the URL and the date. Measuring my own output against the policy''s MaxMessageLength, MaxSegments and required opt-out phrase costs me nothing and is the only point in the whole procedure where the comparison is both possible and still preventable. Doing it afterward, as the retrospective witnesses do, tells someone what I did wrong. Doing it here stops it.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-publisher-am-i-authorized-to-act', 'notification-publisher', 'loop-01', 'Before I transmit, has every human authorization my instructions depend on actually been granted?', 'policy-07 tells me to enforce channel rules and send APPROVED messages. I am not competent to judge whether a message should exist -- that is the communications manager''s approval and the employment counsel''s review. What I am competent to do is refuse to act until both are recorded as granted. Today I have no such column, which means I have been treating the absence of an objection as an approval. That is the inverted default and it is how an AI drafting agent''s self-approval ended up on a live send. I want the gate to require positive evidence of authorization, so that missing data blocks me instead of releasing me.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-publisher-refusal-was-honored', 'notification-publisher', 'loop-01', 'When a gate refused, did the transmission actually stop -- and did I invoke the documented exception instead?', 'This is the only question I ask about the past, and I ask it about myself. A gate that computes a refusal which is then ignored is worse than no gate: it produces a durable record proving we knew and proceeded anyway, which is the fact pattern that turns a compliance finding into a willfulness finding. exc-no-sms-consent tells me precisely what to do when the consent gate refuses -- suppress SMS, send approved email only. So the check is two-part: did I stop, and did I take the documented alternative rather than simply dropping the recipient. Silently dropping someone is not compliance, it is a different failure wearing compliance''s clothes.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-close-auto-authority-current', 'close-automation', 'loop-01', 'Before I execute close-01, close-02, or close-07: is my own role assignment currently valid, and is the agent named in that assignment actually me?', 'I am a pipeline. I must not act on a step whose role has been reassigned out from under me, or whose assignment window has lapsed. `ra-notify-pipeline-2026` proves assignments can be scoped to a platform release; a v5.3 rollout could supersede close-pipeline''s authority mid-quarter and today NOTHING would stop me from posting entries anyway. This is my single most important pre-condition.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-close-auto-input-freshness', 'close-automation', 'loop-01', 'Before I extract in close-02: is every operational binding this step reads inside its freshness SLA, and is it the authoritative one?', '`issue-close-feed` already happened to me — a feed was 17 minutes old against a 15-minute SLA on `bind-close-erp`, and I extracted anyway. `verify-feed-time` states the expectation as a signal, but nothing in the model refuses to let me run. I need per-step aggregate freshness, not a per-binding fact I have to interpret myself.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-close-auto-last-run-clean', 'close-automation', 'loop-01', 'Did my previous run leave anything unresolved — an open issue, a WARN, or a deviation — that I should refuse to run on top of?', '`se-close02` carries VerificationResult=WARN and a Deviation, and `issue-close-feed` hangs off it. A pipeline that starts a new quarter without checking whether its own last quarter closed clean is a pipeline that laminates errors. I need a per-agent, per-run cleanliness verdict I can read in one column.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-close-auto-blocking-requirements-evaluated', 'close-automation', 'loop-01', 'For each step I am about to run, has every blocking requirement attached to it actually been evaluated — or am I about to execute past a control that nobody scored?', '`sr-c01` binds `req-close-cutoff` (blocking) to close-01 and `sat-close-cutoff` scores it. But `sr-c03b` binds `req-close-evidence` to close-03 and `sr-c08` binds it to close-08 — and there is no RequirementSatisfaction row for either. A blocking retention control on the step where I archive evidence is completely unevaluated. I need to see that as a number, not infer it from an absence.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-close-auto-human-override-drift', 'close-automation', 'loop-01', 'Am I drifting? Are humans overriding or correcting my output more often now than they used to?', 'This is my self-assessment question and it is the one I currently cannot ask at all. `se-close02` was corrected by a human (controller-approved rerun) and that fact exists only as prose in a Deviation string. If my override rate is climbing across quarters, the model should say so as a number before a human notices as a feeling. Note that a rising override rate is not automatically bad — it may mean humans are watching more closely — but it must be visible either way.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-hr-authority-without-review', 'hr-policy-owner', 'loop-01', 'I am the AuthorityRole on cr-policy-delivery and it has been UnderReview with no DecidedAt since 2026-07-19. What decisions are waiting on me personally, and how long have they been waiting?', 'Being an authority means decisions queue on my name. cr-policy-delivery is the vehicle for closing gap-policy-delivery-receipts on a live policy version — my inaction is load-bearing for someone else''s remediation. The model records the AuthorityRole and the RequestedAt and never once resolves the pair into ''Elena owes a decision, and it is N days late''. I would rather the model embarrass me than have the gap stay open.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-hr-ai-authored-commitments', 'hr-policy-owner', 'loop-01', 'kf-policy-ai-boundary says AI may draft but may not create legal commitments. policy-03 and policy-06 are both assigned to policy-drafting-agent and se-policy03 was executed by policy-drafting-ai. Is that boundary actually being held?', 'This is the single commitment in the whole policy procedure that I would be asked about under oath. We wrote down the rule — AI drafts, humans commit — as an Approved Explicit fragment sourced from counsel. Then we built a procedure where an AI executes drafting steps and a pipeline sends the results. Whether the human approval step actually sits between them is a structural property nobody checks. If policy-05 were ever skipped or executed by software, the boundary would be violated and the model would say nothing.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-hr-unapproved-knowledge-in-my-name', 'hr-policy-owner', 'loop-01', 'kf-policy-manager-route is Status=Reviewed and I am its OwnerRole. exc-unreachable routes real employee cases on that exact 48-hour rule. Which claims am I the owner of that were never approved?', 'The knowledge authority asks whether the procedure runs on unapproved knowledge. I ask a narrower and more uncomfortable version: which of those unapproved claims are mine. OwnerRole on kf-policy-manager-route is hr-policy-owner — me — and its Status is Reviewed. I own a belief that governs how we treat an unreachable employee, and I never finished approving it. That is a personal accountability question, not a governance statistic.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-hr-what-was-actually-sent', 'hr-policy-owner', 'loop-01', 'policy-07 sends approved communications under channel controls, and kf-policy-channel says disputes are resolved against the complete approved email. If an employee disputes what they received, can I show that what was sent matched what I approved?', 'This is the question I will actually be asked in a dispute, and it is the one this model is furthest from answering. policy-05 is where I approve meaning; policy-06 renders; policy-07 sends. Between approval and delivery sit a drafting AI and a notification pipeline, and the model records no link at all from a sent message back to the approval that authorized it. MessageTemplates and CommunicationPolicies exist as specifications; nothing records an instance.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-hr-policy-knowledge-half-life', 'hr-policy-owner', 'loop-01', 'policy-v1.0.0 was issued 2026-06-01 on knowledge elicited in May from Amina, Noah and me. My stewardship promises a 60-day cadence. Is the policy I own now resting on knowledge older than the policy itself has been reviewed?', 'Employment policy is where stale knowledge becomes legal exposure — a jurisdictional rule that changed, a consent requirement that moved, a channel constraint that a provider silently altered. My 60-day cadence is the tightest in the model precisely because policy knowledge decays fast. But cadence governs the REVIEW; nothing governs the KNOWLEDGE. A version can be reviewed perfectly on schedule while every fragment underneath it quietly ages past usefulness, and both facts live in this model without ever meeting.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-variance-ai-authority-provenance', 'variance-review-agent', 'loop-01', 'By what authority am I executing close-04, when did that authority begin, who approved it, and who held this role before me?', 'This is the question almost no enterprise can answer about its own automated controls: which of our controls are now executed by a non-human, since when, and under what approval. Everything needed is already in `RoleAssignments` as data — `ra-old-variance` and `ra-new-variance` — but it is inert. Nothing surfaces ''this role changed species'', nothing names the approving authority, and nothing links the handover to a ChangeRequest. I need my own provenance as columns before I act.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-variance-ai-quality-vs-human-baseline', 'variance-review-agent', 'loop-01', 'Since I took over on 2026-04-01, is my triage quality better or worse than maria-chen''s during the 2025-01-01 to 2026-03-31 human pilot?', '''Did quality change at the handover'' is the question a regulator asks and nobody can answer. The human pilot period was preserved deliberately — `ra-old-variance` is Superseded, not deleted — so a baseline EXISTS. But quality is currently unmeasurable for either side, because no decision-grain record exists. The same predicates must evaluate on both agents so the comparison is apples-to-apples rather than two different narratives.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-variance-ai-boundary-compliance', 'variance-review-agent', 'loop-01', 'Am I operating inside my approved boundary — or have I made a decision that `kf-policy-ai-boundary` says only a human may make?', '`kf-policy-ai-boundary` states: ''AI may draft from approved sources but may not create new legal commitments or approve meaning.'' It is Approved, IsCurrentlyValid=TRUE, owned by employment-counsel. It is a real, ratified constraint on AI conduct — and NOTHING IN THE MODEL ENFORCES IT. It is a sentence in a Statement column. The same is true for me on the finance side: `req-close-human-approval` says controller and CFO approvals must be human-confirmed, but no column would stop an AI-held role from producing an approval. I want my own boundary to be machine-checkable, because an unenforced boundary is not a boundary.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-variance-ai-human-confirmation-present', 'variance-review-agent', 'loop-01', 'close-04''s instruction says ''Use AI triage, then apply human judgment.'' Did a human actually confirm my material and escalated calls, or did my output pass through unreviewed?', '`se-close04` records the Deviation ''Human analyst confirmed all material escalations.'' — that is the entire evidence that human-in-the-loop happened, and it is a free-text string an AI wrote about itself. `Steps.RequiresHumanConfirmation` exists as a raw boolean on the specification side but nothing on the execution side tests against it. If I am the AI holding this control, the single thing that keeps me legitimate is that a human looked. I want that as a count, not a sentence.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-variance-ai-knowledge-currency', 'variance-review-agent', 'loop-01', 'Is the judgment knowledge I triage against still valid, still owned by someone, and has it been reviewed since I took over the role?', 'I classify variances against `kf-close-fx-time`, `kf-close-top-ten`, and `kf-close-judgment` — all Approved, all sourced from devon-okafor during `elicit-close-shadow` on 2026-04-03, all owned by the controller role. Two problems I cannot currently see: whether that knowledge has been re-reviewed since the AI handover on 2026-04-01, and whether its owning role still has a human holder. If the controller role ever went non-human, AI judgment would be validated by AI-owned knowledge with no human anywhere in the loop, and nothing would say so.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-policy-ai-no-role-assignment', 'policy-drafting-agent', 'loop-01', 'I am named as `policy-drafting-agent`.CurrentAgent and I executed `se-policy03` — but is there any RoleAssignment row that actually grants me this role?', 'There is not. `RoleAssignments` contains rows for finance-analyst, controller, cfo, hr-policy-owner, employment-counsel, notification-publisher, and both sides of variance-review-agent. There is NO row for policy-drafting-agent, close-automation, communications-manager, process-steward, or knowledge-authority. `Roles.CurrentAgent` says I hold the role; nothing time-bounds or authorizes it. An AI that drafts employment policy on the strength of a denormalized pointer, with no valid-from, no approving authority, and no change request, is exactly the gap `ra-new-variance` was built to close for the variance role — and nobody closed it for me.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-policy-ai-source-approval', 'policy-drafting-agent', 'loop-01', 'Before I draft: is every resource I am about to read an approved source, and is its binding still inside its freshness SLA?', '`req-policy-source` is blocking — ''Drafting may use only approved source resources and validated elicitation records'' — and `verify-policy-source` expects unapproved-source-count = 0. But `Resources` has no approval column at all. Eight resources exist and not one carries a status. `sat-policy-source` claims ''Draft provenance contains only approved source and elicitation records'' as free text scored by a human. The blocking control on my own step is evaluated by assertion. I want it evaluated by arithmetic.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-policy-ai-commitment-boundary', 'policy-drafting-agent', 'loop-01', 'Did I draft language that creates a new legal commitment — the one thing `kf-policy-ai-boundary` says I may not do?', 'This is my boundary and it is the model''s clearest example of a ratified constraint with zero enforcement. `kf-policy-ai-boundary` is Approved, Confidence High, sourced from noah-williams during `elicit-policy-interview`, owned by employment-counsel, IsCurrentlyValid TRUE. It says AI ''may not create new legal commitments or approve meaning.'' Nothing in fifty tables tests it. `req-policy-human-approval` says the same thing from the requirement side and is also blocking — and `sr-p05` binds it to policy-05, a step I do not execute, so even that requirement never looks at my output. I want my own leash to be real.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-policy-ai-downstream-rewrite', 'policy-drafting-agent', 'loop-01', 'Is my draft surviving human review, or is `noah-williams` rewriting my legal language every time?', 'My self-assessment question. `se-policy04` is the legal review of my policy-03 draft and it is still InProgress with `sat-policy-legal` at PartiallySatisfied. If counsel systematically rewrites what I produce, I am not drafting — I am generating a first pass that costs a lawyer more time than it saves, and the org should know that as a rate rather than as a lawyer''s private opinion. Note the correct reading is ambiguous: a high rewrite rate might mean I am bad, or might mean counsel is doing exactly the job the boundary assigns them. The number does not settle that; it makes the conversation possible.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-policy-ai-approval-chain-complete', 'policy-drafting-agent', 'loop-01', 'Before `notification-pipeline` sends anything I rendered at policy-06: has a human actually approved the MEANING at policy-05, and has counsel actually signed off at policy-04 — or is my text about to reach employees on the strength of two pending reviews?', 'The exec is live right now. `se-policy04` is InProgress, `sat-policy-legal` is PartiallySatisfied (''Review started; final approval pending''), and there is no step execution for policy-05 at all. Both `req-policy-legal` and `req-policy-human-approval` are blocking. The step ordering says policy-06 comes after policy-05 — but ordering is a `StepTransitions` row, not a gate. Nothing in the model prevents policy-06 from executing while the two human approvals ahead of it are unfinished, and I am the agent that would execute it. I want the gate to exist before I am the reason it was needed.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

