-- ----------------------------------------------------------------------------
-- DeliveredCommunications: Everything above is a proxy for the real question, which is instance-level: THIS message, to THIS recipient, rendered from THIS template, authorized by THIS approval. The model has MessageTemplates and CommunicationPolicies as specifications and no record of a single thing ever sent. Without an instance table, 'can I show that what was sent matched what I approved' is permanently unanswerable rather than merely unanswered — and it is the question a disputing employee actually asks. Extension term (urn:effortless:pko-extension#DeliveredCommunication); PKO has no native class for a delivered artifact instance.
-- ----------------------------------------------------------------------------
INSERT INTO delivered_communications (delivered_communication_id, procedure_execution, sending_step_execution, authorizing_step_execution, message_template, channel, recipient_key, sent_at, rendered_content_hash, approved_content_hash, delivery_status, semantic_type_iri)
